shapes.frame_eqs_str:
sample=.002*instance;


///// Sphere
r1=1;
q10= -1+2*sample;
q11=200*sample;

my_x = sqrt(r1*r1-q10*q10)*cos(q11);
my_y = sqrt(r1*r1-q10*q10)*sin(q11);
my_z = q10;

/////// rotations... by flexi

d = 6;
zoom = 10;

w3 = q1;
w2 = q2;
w1 = q3;

x1 = cos(w1)*my_x + sin(w1)*my_y;
y1 = -sin(w1)*my_x + cos(w1)*my_y;
z1 = my_z;

x2 = cos(w2)*x1 + sin(w2)*z1;
z2 = -sin(w2)*x1 + cos(w2)*z1;
y2 = y1;

y3 = cos(w3)*y2 + sin(w3)*z2;
z3 = -sin(w3)*y2 + cos(w3)*z2;
x3 = x2;

// perspective calculation

l = sqrt(x3*x3 + y3*y3);
w = atan2(x3,y3);
p = tan(asin(1) + atan2(d+z3,l));
d = sqrt(x3*x3 + y3*y3 + (z3+d)*(z3+d));

my_x = zoom*sin(w)*p;
my_y = zoom*cos(w)*p;

x = 0.5 + my_x/q6;
y = 0.5 + my_y/q5;


rad=.1*sample;
ang=sample*time*15;

b=sample;
g=b;
r=b;

